class Solution:
    def minStoneSum(self, piles, k):
        piles = list(piles)
        for _ in range(k):
            mi = 0
            for i in range(1, len(piles)):
                if piles[i] > piles[mi]:
                    mi = i
            if piles[mi] <= 1:
                break
            piles[mi] -= piles[mi] // 2
        return sum(piles)

