import heapq
class Solution:
    def minStoneSum(self, piles, k):
        h = [-p for p in piles]
        heapq.heapify(h)
        for _ in range(k):
            if -h[0] <= 1:
                break
            p = -heapq.heappop(h)
            p -= p // 2
            heapq.heappush(h, -p)
        return -sum(h)

