var minStoneSum = function(piles, k) {
    const heap = piles.slice();
    const n = heap.length;
    const down = (i) => {
        while (true) {
            let l = 2 * i + 1, r = 2 * i + 2, m = i;
            if (l < heap.length && heap[l] > heap[m]) m = l;
            if (r < heap.length && heap[r] > heap[m]) m = r;
            if (m === i) break;
            [heap[i], heap[m]] = [heap[m], heap[i]];
            i = m;
        }
    };
    for (let i = (n >> 1) - 1; i >= 0; i--) down(i);
    for (let op = 0; op < k; op++) {
        if (heap[0] <= 1) break;
        heap[0] -= heap[0] >> 1;
        down(0);
    }
    let sum = 0;
    for (const v of heap) sum += v;
    return sum;
};
